select.isEqual:
SELECT COUNT(TBAPRRECEIPTPROCESSINFO.DOCID) FROM EZAPPROVALG_${companyID}.TBAPRRECEIPTPROCESSINFO INNER JOIN EZAPPROVALG_${companyID}.TBAPRDOCINFO ON TBAPRRECEIPTPROCESSINFO.DOCID = TBAPRDOCINFO.DOCID AND TBAPRRECEIPTPROCESSINFO.TENANT_ID = TBAPRDOCINFO.TENANT_ID INNER JOIN EZAPPROVALG_${companyID}.TBEXPAPRDOCINFO ON TBEXPAPRDOCINFO.DOCID = TBAPRDOCINFO.DOCID AND TBEXPAPRDOCINFO.TENANT_ID = TBAPRDOCINFO.TENANT_ID WHERE TBAPRRECEIPTPROCESSINFO.PROCESSYN <> ''Y'' AND (((TBAPRRECEIPTPROCESSINFO.PROCESSORID = #v_USERID# AND TBAPRRECEIPTPROCESSINFO.RECEIVEDDEPTID = #v_DEPTID#) AND (TBAPRRECEIPTPROCESSINFO.APRSTATE = '012' OR TBAPRRECEIPTPROCESSINFO.APRSTATE = '015')) AND TBAPRRECEIPTPROCESSINFO.TENANT_ID =#v_TENANTID#
OR (TBAPRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN (#v_DEPTIDS#) AND TBAPRRECEIPTPROCESSINFO.APRSTATE IN ('011', '014')) OR (TBAPRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN (#v_DEPTIDS#) AND TBAPRRECEIPTPROCESSINFO.APRSTATE = '015')
)

